VALUES
  ('judicial-f0899a01-moex-00006', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關法律變更的敘述，下列何者正確？', '["依刑法第2條第1項本文之規定，行為後法律有變更時，原則上適用裁判時之法律", "刑法第2條第1項所稱之法律，僅限於涉及犯罪成立之要件，而不含刑罰效果", "依刑法第2條第2項之規定，沒收與所有的保安處分均適用裁判時之法律", "刑罰之內容於行為後有變更者，結論上應適用最有利於行為人之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00007', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依刑法規定、實務及通說見解，下列何者之情形不該當刑法上之重傷概念？', '["甲將乙右手大拇指、食指及中指砍斷，僅留無名指與小指", "甲用球棒毆打乙，使乙之膝關節無法伸直", "甲用球棒毆打乙，使乙昏迷成為植物人", "甲用球棒毆打乙，使乙腳骨折經一年復健始能正常行走"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00008', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲為A上市公司執行長，某日酒駕肇事，乃與坐在副手座的乙交換，並提供新臺幣300萬元安家費，要乙 承認自己為駕駛人。依實務見解，下列何者正確？', '["甲成立刑法第164條第2項意圖隱避犯人頂替罪之教唆犯", "乙成立刑法第164條第2項意圖隱避犯人頂替罪之幫助犯", "甲成立刑法第164條第2項的意圖隱避犯人頂替罪", "乙成立刑法第164條第2項的意圖隱避犯人頂替罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00009', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關罪刑法定原則，下列敘述何者錯誤？', '["其目的在防止國家濫用刑罰，並藉此保障人民權利", "國家必須事先以成文法律明確規定犯罪要件與制裁內容", "習慣法不得作為成立犯罪之依據", "保安處分一律適用裁判時之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00010', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '意圖抬高交易價格，囤積下列何種物品，無正當理由不應市銷售者，不構成刑法第251條不法囤積物品哄 抬價格牟利罪？', '["糧食、農產品或其他民生必需之飲食物品", "種苗、肥料、原料或其他農業、工業必需之物品", "經行政院公告之生活必需用品", "衣服、鞋子等服飾物品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00011', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關客觀歸責理論中之信賴原則的敘述，下列何者正確？', '["若得主張信賴原則，就欠缺期待可能性", "甲跨越雙黃線逆向行駛，仍得信賴他車會閃避", "甲依道路交通規則駕駛汽車，雖見路人違規穿越道路，仍未減速而碰撞該路人，甲不得主張信賴原則", "主治醫師甲任由護理師獨自執行醫療行為，針對護理師的醫療過失，基於醫療分工原則，甲仍得主張信 賴原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00012', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑法未遂犯，下列敘述何者正確？', '["形式預備犯亦屬未遂犯", "未遂犯係指已著手於犯罪之實行而不遂", "行為人已著手於犯罪行為之實行， 但其行為不能發生犯罪之結果 ，又無危險者，其法律效果為減輕或 免除其刑", "行為人已著手於犯罪行為之實行，但因己意中止者，其法律效果為不罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00013', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲於夜間行走時，看見仇人乙手持棍狀物站在前方，因甲以為乙要襲擊自己，於是隨手撿起路邊的石頭朝 乙扔去，造成乙頭破血流；甲事後發現乙手持的只是其剛買的棍狀法國麵包。關於甲之行為，下列何者正 確？', '["屬於容許錯誤", "屬於容許構成要件錯誤", "屬於反面的容許構成要件錯誤", "屬於包攝錯誤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00014', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑法之共同正犯，下列敘述何者錯誤？', '["二人以上共同實行犯罪之行為者，為共同正犯", "以自己共同犯罪之意思，事先同謀，而由其中一部分人實施犯罪之行為者，僅有親自實施犯罪行為之人 為正犯，未實施者為共犯", "刑法第339條之4第1項第2款規定：「三人以上共同犯之」，始成立加重詐欺罪。如僅有二人共同犯詐 欺罪，不成立該款之加重詐欺罪", "共同正犯之意思聯絡，原不以數人間直接發生者為限，即有間接之聯絡者，亦包括在內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00015', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於構成要件錯誤，下列敘述何者正確？', '["甲欲射殺乙，因手抖誤擊旁邊的丙，此為客體錯誤", "甲欲射殺乙，卻誤丙為乙而射殺丙，甲成立刑法第271條第1項殺人既遂罪", "甲欲射殺乙，卻因手抖擊傷旁邊的A犬，甲成立刑法第271條第1項殺人既遂罪", "甲欲射殺A犬，卻因手抖而誤擊旁邊的乙，致乙死亡，甲成立刑法第271條第1項殺人既遂罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
